parameters.jsCode:
const aiRaw = $input.first().json.message.content;
let triage;

try {
  triage = JSON.parse(aiRaw);
} catch(e) {
  // Fallback if JSON parse fails
  triage = {
    severity: 'P2',
    severity_reason: 'Could not parse AI response — defaulting to P2',
    assignee_area: 'general',
    assignee_reason: 'Could not parse AI response',
    suggested_labels: ['needs-triage'],
    summary: 'Manual review required',
    needs_immediate_alert: false
  };
}

// Bring forward the issue context from previous node
const issue = $('Extract Issue Data').first().json;

return [{
  json: {
    ...issue,
    severity: triage.severity,
    severity_reason: triage.severity_reason,
    assignee_area: triage.assignee_area,
    assignee_reason: triage.assignee_reason,
    suggested_labels: triage.suggested_labels || [],
    summary: triage.summary,
    needs_immediate_alert: triage.needs_immediate_alert || false,
    slack_color: triage.severity === 'P0' ? '#FF0000' :
                 triage.severity === 'P1' ? '#FF8C00' :
                 triage.severity === 'P2' ? '#FFD700' : '#36a64f'
  }
}];
